 using System.ComponentModel;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 const string modelId = "gpt-4o-mini-2024-07-18";

 // --- Build the IChatClient via MEAI abstraction ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Define tools ---
 var notepad = new Notepad();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(
         (string query) =>
         {
             Console.WriteLine($"  🔍  Searching: {query}");
             return WebSearch.SearchAsync(query);
         },
         "web_search",
         "Searches the web for the given query and returns a list of result snippets. "
         + "Use this to gather information about a research topic."),

     AIFunctionFactory.Create(
         ([Description("A concise note capturing a key finding")] string note) =>
         {
             notepad.Add(note);
             Console.WriteLine($"  📝  Note saved ({notepad.Count} total)");
             return "Note saved.";
         },
         "save_note",
         "Saves a research note. Call this for every important finding so nothing is lost."),

     AIFunctionFactory.Create(
         () => notepad.GetAll(),
         "get_notes",
         "Returns all notes saved so far. Use before writing the final summary."),
 };

 // --- Create the agent with Microsoft Agent Framework ---
 var agent = new ChatClientAgent(
     chatClient,
     new ChatClientAgentOptions
     {
         Name = "ResearchAgent",
         Description = "An agent that researches a topic by searching the web and taking notes.",
         ChatOptions = new ChatOptions
         {
             Temperature = 0f,
             MaxOutputTokens = 2048,
             Tools = [.. tools],
             Instructions = """
                 You are a research assistant. Given a topic you must:
                 1. Use the web_search tool several times with varied queries to gather broad information.
                 2. Use save_note after each search to record the most important findings.
                 3. When you have enough material, call get_notes to review everything.
                 4. Produce a well-structured markdown summary with sections, bullet points, and source attributions.
                 Keep searches focused and notes concise. Aim for 3-5 searches before summarizing.
                 """,
         },
     });

 // --- Run the agent ---
 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       🔬 Research Agent              ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();

 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine();
 Console.WriteLine($"Researching: {topic}");
 Console.WriteLine(new string('─', 40));

 var session = await agent.CreateSessionAsync();

 AgentResponse response = await agent.RunAsync(
     $"Research the following topic and produce a summary: {topic}",
     session);

 Console.WriteLine();
 Console.WriteLine(new string('═', 40));
 Console.WriteLine("RESEARCH SUMMARY");
 Console.WriteLine(new string('═', 40));
 Console.WriteLine(response.Text);

 // ════════════════════════════════════════
 // Tool implementations
 // ════════════════════════════════════════

 /// <summary>Simple in-memory notepad for the agent to accumulate findings.</summary>
 sealed class Notepad
 {
     private readonly List<string> _notes = [];

     public int Count => _notes.Count;

     public void Add(string note) => _notes.Add(note);

     public string GetAll() =>
         _notes.Count == 0
             ? "No notes yet."
             : string.Join('\n', _notes.Select((n, i) => $"{i + 1}. {n}"));
 }

 /// <summary>Web search via DuckDuckGo Lite (no API key required).</summary>
 static class WebSearch
 {
     private static readonly HttpClient Http = new()
     {
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0" },
         },
     };

     public static async Task<string> SearchAsync(string query)
     {
         try
         {
             var url = $"https://lite.duckduckgo.com/lite/?q={Uri.EscapeDataString(query)}";
             var html = await Http.GetStringAsync(url);
             var snippets = ParseSnippets(html);

             return snippets.Count == 0
                 ? "No results found."
                 : string.Join("\n\n", snippets.Take(5));
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     private static List<string> ParseSnippets(string html)
     {
         // DuckDuckGo Lite returns results in <td> elements with class "result-snippet"
         var results = new List<string>();
         var snippetMarker = "class=\"result-snippet\"";
         var linkMarker = "class=\"result-link\"";
         var idx = 0;

         while (idx < html.Length && results.Count < 5)
         {
             // Find a result link
             var linkIdx = html.IndexOf(linkMarker, idx, StringComparison.Ordinal);
             if (linkIdx < 0) break;

             var linkText = ExtractTagContent(html, linkIdx);

             // Find corresponding snippet
             var snippetIdx = html.IndexOf(snippetMarker, linkIdx, StringComparison.Ordinal);
             if (snippetIdx < 0) break;

             var snippet = ExtractTagContent(html, snippetIdx);
             idx = snippetIdx + 1;

             if (!string.IsNullOrWhiteSpace(snippet))
             {
                 var title = string.IsNullOrWhiteSpace(linkText) ? "Result" : linkText.Trim();
                 results.Add($"[{title}]\n{snippet.Trim()}");
             }
         }

         return results;
     }

     private static string ExtractTagContent(string html, int markerIdx)
     {
         // Find the closing > of the tag that contains the marker
         var tagClose = html.IndexOf('>', markerIdx);
         if (tagClose < 0) return string.Empty;

         // Find the next </td> or </a>
         var endTag = html.IndexOf("</", tagClose, StringComparison.Ordinal);
         if (endTag < 0) return string.Empty;

         var content = html[(tagClose + 1)..endTag];
         // Strip any remaining HTML tags
         return System.Text.RegularExpressions.Regex.Replace(content, "<[^>]+>", " ").Trim();
     }
 }

